init_eqs:
n = -10000; loop (20000, megabuf(n)=0; gmegabuf(n)=0; n +=1; );

MINBPM = 35; MAXBPM = 220; num_res = 512;
index = 0;
loop (num_res,
n = index*8;
BPM      = minbpm * pow(maxbpm/minbpm,index/(num_res-1));
megabuf(n) = BPM;
index += 1;
);


//structure of resonator data, starting at megabuf (0)
//size = 8
//0: BPM
//1: v
//2: y
//3: amplitude
//4: amplitude after harmonics post processing
//5: beatcos
//6: beatsin


pi = 3.1416;
reg00 = num_res;

frame_eqs:
dt = min (1/fps,0.1) ; //Stability !
dec_m = 1 - 4*dt; dec_s = 1 - 1.25*dt;
vol =  (bass+mid+treb);

vol_ = vol_*dec_m + (1-dec_m)*vol; exc = vol-vol_;
excite = atan (exc*2)/1.6;

index=0; ratio = log(maxbpm/minbpm); maxquad = .5; meanquad = 0;
loop (num_res,
n = index*8;
omega      =   megabuf(n) * 6.2832/60;
megabuf (n+1) *= 1-0.22*dt; //damping
EC_Steps = int (10*omega*dt)+1;
loop (EC_Steps, // Euler-Cauchy steps
megabuf (n+1) += (excite - sqr(omega)*megabuf(n + 2)) * dt/EC_Steps;
megabuf (n+2) += megabuf(n+1) * dt/EC_Steps);
beatcos  = megabuf(n+1);
beatsin = megabuf(n+2)*omega; //2pi/60
quad     = sqrt (pow(beatsin,2) + pow(beatcos,2)) ;
if (maxquad < quad, maxquad = quad, 0);
meanquad += quad / num_res;
megabuf (n+3) = megabuf(n+3) *dec_s +  quad* (1-dec_s);
megabuf (n+4) = megabuf(n+3);
megabuf (n+5) = beatcos;
megabuf (n+6) = beatsin ;
index += 1;
);

n = 0; maxind = 0;
loop (num_res,
scale =  (1+megabuf(n+3)/2)/3;
if (megabuf(n+3) > megabuf(maxind+3), maxind = n, 0);
gmegabuf(n+5) = megabuf(n+5) * scale;
gmegabuf(n+6) = megabuf(n+6) * scale;
n+=8;);


sig0 = sig;
sig = megabuf(maxind+6);
gp = (maxquad* (1+gp*0.3) > 3.5*meanquad );
prog += (sig*sig0 <0) * gp;
q27 = ((prog%8)/4-1);

gp2 = (maxquad* (1+gp2*0.3) > 7*meanquad );
prog2 += (sig*sig0 <0) * gp2;
q28 = prog2/3;
flash = if ((sig*sig0 < 0)* (maxquad > 8.5*meanquad),4, flash * 0.5) ;
q29 = flash;
maxind0 = maxind;

n = 0; imax = 0;
loop (num_res,
q12 += megabuf(n*8+1);
q13 += megabuf(n*8+2);
n+=1;);

maxquad_ = maxquad_*dec_m + (1-dec_m)*maxquad;
q1 = sqrt(3/maxquad_);
tr2 += maxquad_/fps;
q2 = tr2*1.85; //vert. mov. muster

q3 = 0.01; //scale x-shift shapes

q32 = aspecty;


monitor = q15;

wave_0_per_point:
num_inst = reg00;
instance = t1;

rx1 = gmegabuf (instance*8+5);
rx2 = gmegabuf ((num_inst-instance-1)*8+5); //mirrored

ry1 = gmegabuf (instance*8+6);
ry2 = gmegabuf ((num_inst-instance-1)*8+6);//mirrored

kx = 0.1* q1;
ky = 0.15 * q1;


x0 = (rx1 - rx2)*kx * (abs (sample-0.5)*2+0);;

cx = 0.75 ;
x = x0+(1-cx)/2 + cx*sample + q13*q3 * (abs(sample-0.5)-0.);


y0 = (ry1+ry2)*ky + .0*q13*(abs(sample-0.5)-0.3);
y = y0+0.55;


ang1 = atan2 (x0,y0);

a = 0.5 + sin(ang1)/3;

r = 0.5 + 0.3*sin(rx1*12+sample*12+2);
g = 0.5 + 0.3*sin(rx2*12+sample*12+1);
b = 0.5 + 0.3*sin(ry1*12+sample*12);


t1 += 1;
